  9→protocol TestCaseRunShowCommandServicing {
 10→    func run(
 11→        project: String?,
 12→        testCaseRunId: String,
 13→        path: String?,
 14→        json: Bool
 15→    ) async throws
 16→}
 17→
 18→enum TestCaseRunShowCommandServiceError: Equatable, LocalizedError {
 19→    case missingFullHandle
 20→
 21→    var errorDescription: String? {
 22→        switch self {
 23→        case .missingFullHandle:
 24→            return "We couldn't show the test case run because the project is missing. You can pass either its value or a path to a Tuist project."
 25→        }
 26→    }
 27→}
 28→
 29→struct TestCaseRunShowCommandService: TestCaseRunShowCommandServicing {
 30→    private let getTestCaseRunService: GetTestCaseRunServicing
 31→    private let serverEnvironmentService: ServerEnvironmentServicing
 32→    private let configLoader: ConfigLoading
 33→
 34→    init(
 35→        getTestCaseRunService: GetTestCaseRunServicing = GetTestCaseRunService(),
 36→        serverEnvironmentService: ServerEnvironmentServicing = ServerEnvironmentService(),
 37→        configLoader: ConfigLoading = ConfigLoader()
 38→    ) {
 39→        self.getTestCaseRunService = getTestCaseRunService
 40→        self.serverEnvironmentService = serverEnvironmentService
 41→        self.configLoader = configLoader
 42→    }
 43→
 44→    func run(
 45→        project: String?,
 46→        testCaseRunId: String,
 47→        path: String?,
 48→        json: Bool
 49→    ) async throws {
 50→        let directoryPath: AbsolutePath = try await Environment.current.pathRelativeToWorkingDirectory(path)
 51→
 52→        let config = try await configLoader.loadConfig(path: directoryPath)
 53→        guard let resolvedFullHandle = project ?? config.fullHandle else {
 54→            throw TestCaseRunShowCommandServiceError.missingFullHandle
 55→        }
 56→
 57→        let serverURL = try serverEnvironmentService.url(configServerURL: config.url)
 58→
 59→        let run = try await getTestCaseRunService.getTestCaseRun(
 60→            fullHandle: resolvedFullHandle,
 61→            testCaseRunId: testCaseRunId,
 62→            serverURL: serverURL
 63→        )
 64→
 65→        if json {
 66→            try Noora.current.json(run)
 67→            return
 68→        }
 69→
 70→        let info = formatRunInfo(run)
 71→        Noora.current.passthrough("\(info)")
 72→
 73→        if !run.attachments.isEmpty {
 74→            Noora.current.passthrough("\("Attachments (\(run.attachments.count))".bold())\n")
 75→            for attachment in run.attachments {
 76→                Noora.current.passthrough("  \(.link(title: attachment.file_name, href: attachment.url))\n")
 77→            }
 78→        }
 79→
 80→        if let crashReport = run.crash_report {
 81→            var summary: [String] = []
 82→            summary.append("Crash Report".bold())
 83→            if let exceptionType = crashReport.exception_type, !exceptionType.isEmpty {
 84→                summary.append("  Exception: \(exceptionType)")
 85→            }
 86→            if let signal = crashReport.signal, !signal.isEmpty {
 87→                summary.append("  Signal:    \(signal)")
 88→            }
 89→            if let subtype = crashReport.exception_subtype, !subtype.isEmpty {
 90→                summary.append("  Subtype:   \(subtype)")
 91→            }
 92→            Noora.current.passthrough("\(summary.joined(separator: "\n"))\n")
 93→            if let attachmentURL = crashReport.attachment_url {
 94→                Noora.current.passthrough("  \(.link(title: "Full crash report", href: attachmentURL))\n")
 95→            }
 96→            if let triggeredThreadFrames = crashReport.triggered_thread_frames, !triggeredThreadFrames.isEmpty {
 97→                Noora.current.passthrough("\n\(triggeredThreadFrames)\n")
 98→            }
 99→        }
100→        Noora.current.passthrough("")
101→    }
102→
103→    private func formatRunInfo(_ run: ServerTestCaseRun) -> String {
104→        var info: [String] = []
105→
106→        // Test identity
107→        var testName = "\(run.module_name)"
108→        if let suiteName = run.suite_name, !suiteName.isEmpty {
109→            testName += "/\(suiteName)"
110→        }
111→        testName += "/\(run.name)"
112→        info.append(testName.bold())
113→
114→        // Result
115→        info.append("")
116→        info.append("Result".bold())
117→        info.append("  Status:    \(run.status.rawValue)")
118→        info.append("  Duration:  \(Formatters.formatDuration(run.duration))")
119→        info.append("  Flaky:     \(run.is_flaky ? "Yes" : "No")")
120→
121→        // Context
122→        info.append("")
123→        info.append("Context".bold())
124→        info.append("  CI:        \(run.is_ci ? "Yes" : "No")")
125→        if let scheme = run.scheme, !scheme.isEmpty {
126→            info.append("  Scheme:    \(scheme)")
127→        }
128→        if let gitBranch = run.git_branch, !gitBranch.isEmpty {
129→            info.append("  Branch:    \(gitBranch)")
130→        }
131→        if let gitCommitSha = run.git_commit_sha, !gitCommitSha.isEmpty {
132→            info.append("  Commit:    \(gitCommitSha)")
133→        }
134→        if let ranAt = run.ran_at {
135→            info.append("  Ran At:    \(Formatters.formatDate(ranAt))")
136→        }
137→
138→        // IDs
139→        info.append("")
140→        info.append("IDs".bold())
141→        info.append("  Run:       \(run.id)")
142→        if let testRunId = run.test_run_id, !testRunId.isEmpty {
143→            info.append("  Test Run:  \(testRunId)")
144→        }
145→
146→        // Failures
147→        if !run.failures.isEmpty {
148→            info.append("")
149→            info.append("Failures (\(run.failures.count))".bold())
150→            for (index, failure) in run.failures.enumerated() {
151→                if index > 0 { info.append("") }
152→                var location = ""
153→                if let path = failure.path {
154→                    location = path
155→                    if let lineNumber = failure.line_number {
156→                        location += ":\(lineNumber)"
157→                    }
158→                }
159→
160→                var header = ""
161→                if let issueType = failure.issue_type, !issueType.isEmpty {
162→                    header = "  [\(issueType)]"
163→                    if !location.isEmpty { header += " \(location)" }
164→                } else if !location.isEmpty {
165→                    header = "  \(location)"
166→                }
167→
168→                if !header.isEmpty { info.append(header) }
169→                info.append("  \(failure.message)")
170→            }
171→        }
172→
173→        // Repetitions
174→        if !run.repetitions.isEmpty {
175→            info.append("")
176→            info.append("Repetitions (\(run.repetitions.count))".bold())
177→            for repetition in run.repetitions
178→                .sorted(by: { $0.repetition_number < $1.repetition_number })
179→            {
180→                let num = repetition.repetition_number
181→                let status = repetition.status.rawValue
182→                let duration = Formatters.formatDuration(repetition.duration)
183→                info.append("  #\(num): \(status)  \(duration)")
184→            }
185→        }
186→
187→        return info.joined(separator: "\n") + "\n"
188→    }
189→}
