 1→import Foundation
 2→
 3→public enum Formatters {
 4→    private static let byteCountFormatter: ByteCountFormatter = {
 5→        let formatter = ByteCountFormatter()
 6→        formatter.allowedUnits = [.useAll]
 7→        formatter.countStyle = .file
 8→        return formatter
 9→    }()
10→
11→    private static let dateFormatter: DateFormatter = {
12→        let formatter = DateFormatter()
13→        formatter.dateStyle = .medium
14→        formatter.timeStyle = .short
15→        return formatter
16→    }()
17→
18→    public static func formatBytes(_ bytes: Int) -> String {
19→        byteCountFormatter.string(fromByteCount: Int64(bytes))
20→    }
21→
22→    public static func formatDate(_ date: Date) -> String {
23→        dateFormatter.string(from: date)
24→    }
25→
26→    public static func formatDuration(_ milliseconds: Int) -> String {
27→        if milliseconds < 1000 {
28→            return "\(milliseconds)ms"
29→        }
30→        let seconds = Double(milliseconds) / 1000.0
31→        return String(format: "%.2fs", seconds)
32→    }
33→
34→    public static func formatTimestamp(_ timestamp: Int) -> String {
35→        let date = Date(timeIntervalSince1970: TimeInterval(timestamp))
36→        return formatDate(date)
37→    }
38→}
