 1→import Foundation
 2→
 3→enum TestCaseIdentifier {
 4→    case id(String)
 5→    case name(moduleName: String, suiteName: String?, testName: String)
 6→
 7→    init(_ identifier: String) throws {
 8→        if identifier.contains("/") {
 9→            let parts = identifier.split(separator: "/", omittingEmptySubsequences: true).map(String.init)
10→            switch parts.count {
11→            case 3:
12→                self = .name(moduleName: parts[0], suiteName: parts[1], testName: parts[2])
13→            case 2:
14→                self = .name(moduleName: parts[0], suiteName: nil, testName: parts[1])
15→            default:
16→                throw TestCaseIdentifierError.invalidIdentifier(identifier)
17→            }
18→        } else {
19→            self = .id(identifier)
20→        }
21→    }
22→}
23→
24→enum TestCaseIdentifierError: Equatable, LocalizedError {
25→    case invalidIdentifier(String)
26→
27→    var errorDescription: String? {
28→        switch self {
29→        case let .invalidIdentifier(identifier):
30→            return "Invalid test case identifier '\(identifier)'. Expected a UUID or the format Module/Suite/TestCase (or Module/TestCase)."
31→        }
32→    }
33→}
