import ArgumentParser
import Foundation
import Path
import TuistEnvKey
import TuistNooraExtension

public enum BuildListStatus: String, ExpressibleByArgument, CaseIterable {
    case success
    case failure
}

public struct BuildListCommand: AsyncParsableCommand, NooraReadyCommand {
    public init() {}
    public static var configuration: CommandConfiguration {
        CommandConfiguration(
            commandName: "list",
            abstract: "Lists all builds in a project."
        )
    }

    @Option(
        name: [.customLong("project"), .customShort("P")],
        help: "The full handle of the project. Must be in the format of account-handle/project-handle.",
        envKey: .buildListFullHandle
    )
    var fullHandle: String?

    @Option(
        name: .shortAndLong,
        help: "The path to the directory or a subdirectory of the project.",
        completion: .directory,
        envKey: .buildListPath
    )
    var path: String?

    @Option(
        name: .long,
        help: "Filter builds by git branch.",
        envKey: .buildListGitBranch
    )
    var gitBranch: String?

    @Option(
        name: .long,
        help: "Filter builds by status (success or failure).",
        envKey: .buildListStatus
    )
    var status: BuildListStatus?

    @Option(
        name: .long,
        help: "Filter builds by scheme.",
        envKey: .buildListScheme
    )
    var scheme: String?

    @Option(
        name: .long,
        help: "Filter builds by configuration.",
        envKey: .buildListConfiguration
    )
    var configuration: String?

    @Option(
        name: .long,
        parsing: .upToNextOption,
        help: "Filter builds by tags. Returns builds containing ALL specified tags."
    )
    var tags: [String] = []

    @Option(
        name: .long,
        parsing: .upToNextOption,
        help: "Filter builds by custom values (key=value format). Returns builds matching ALL specified values."
    )
    var values: [String] = []

    @Option(
        name: .long,
        help: "The page number to fetch (1-indexed).",
        envKey: .buildListPage
    )
    var page: Int?

    @Option(
        name: .long,
        help: "The number of builds per page. Defaults to 10.",
        envKey: .buildListPageSize
    )
    var pageSize: Int?

    @Flag(
        help: "The output in JSON format.",
        envKey: .buildListJson
    )
    var json: Bool = false

    public var jsonThroughNoora: Bool = true

    public func run() async throws {
        try await BuildListCommandService().run(
            fullHandle: fullHandle,
            path: path,
            gitBranch: gitBranch,
            status: status?.rawValue,
            scheme: scheme,
            configuration: configuration,
            tags: tags,
            values: values,
            page: page,
            pageSize: pageSize,
            json: json
        )
    }
}

import Foundation
import Noora
import Path
import TuistConfigLoader
import TuistEnvironment
import TuistServer

protocol BuildListCommandServicing {
    func run(
        fullHandle: String?,
        path: String?,
        gitBranch: String?,
        status: String?,
        scheme: String?,
        configuration: String?,
        tags: [String],
        values: [String],
        page: Int?,
        pageSize: Int?,
        json: Bool
    ) async throws
}

enum BuildListCommandServiceError: Equatable, LocalizedError {
    case missingFullHandle

    var errorDescription: String? {
        switch self {
        case .missingFullHandle:
            return "We couldn't list builds because the full handle is missing. You can pass either its value or a path to a Tuist project."
        }
    }
}

struct BuildListCommandService: BuildListCommandServicing {
    private let listBuildsService: ListBuildsServicing
    private let serverEnvironmentService: ServerEnvironmentServicing
    private let configLoader: ConfigLoading

    init(
        listBuildsService: ListBuildsServicing = ListBuildsService(),
        serverEnvironmentService: ServerEnvironmentServicing = ServerEnvironmentService(),
        configLoader: ConfigLoading = ConfigLoader()
    ) {
        self.listBuildsService = listBuildsService
        self.serverEnvironmentService = serverEnvironmentService
        self.configLoader = configLoader
    }

    func run(
        fullHandle: String?,
        path: String?,
        gitBranch: String?,
        status: String?,
        scheme: String?,
        configuration: String?,
        tags: [String],
        values: [String],
        page: Int?,
        pageSize: Int?,
        json: Bool
    ) async throws {
        let directoryPath: AbsolutePath = try await Environment.current.pathRelativeToWorkingDirectory(path)

        let config = try await configLoader.loadConfig(path: directoryPath)
        guard let resolvedFullHandle = fullHandle ?? config.fullHandle else {
            throw BuildListCommandServiceError.missingFullHandle
        }

        let serverURL = try serverEnvironmentService.url(configServerURL: config.url)

        let startPage = (page ?? 1) - 1 // Convert to 0-indexed for Noora
        let pageSize = pageSize ?? 10

        let initialBuildsPage = try await listBuildsService.listBuilds(
            fullHandle: resolvedFullHandle,
            serverURL: serverURL,
            gitBranch: gitBranch,
            status: status,
            scheme: scheme,
            configuration: configuration,
            tags: tags,
            values: values,
            page: startPage + 1, // API uses 1-indexed pages
            pageSize: pageSize
        )

        let initialBuilds = initialBuildsPage.builds

        if json {
            try Noora.current.json(initialBuilds)
            return
        }

        if initialBuilds.isEmpty {
            var filters: [String] = []
            if let gitBranch { filters.append("branch: \(gitBranch)") }
            if let status { filters.append("status: \(status)") }
            if let scheme { filters.append("scheme: \(scheme)") }
            if let configuration { filters.append("configuration: \(configuration)") }
            if !tags.isEmpty { filters.append("tags: \(tags.joined(separator: ", "))") }
            if !values.isEmpty { filters.append("values: \(values.joined(separator: ", "))") }
            let filterDescription = filters.isEmpty ? "" : " with filters: \(filters.joined(separator: ", "))"
            if let page {
                Noora.current
                    .passthrough("No builds found on page \(page) for project \(resolvedFullHandle)\(filterDescription).")
            } else {
                Noora.current.passthrough("No builds found for project \(resolvedFullHandle)\(filterDescription).")
            }
            return
        }

        let totalPages = initialBuildsPage.pagination_metadata.total_pages ?? 1

        let initialRows = initialBuilds.map { build in
            [
                build.id,
                build.status.rawValue,
                build.scheme ?? "-",
                build.configuration ?? "-",
                formatDuration(build.duration),
                build.is_ci ? "Yes" : "No",
                formatDate(build.inserted_at),
            ]
        }

        try await Noora.current.paginatedTable(
            headers: ["ID", "Status", "Scheme", "Configuration", "Duration", "CI", "Date"],
            pageSize: pageSize,
            totalPages: totalPages,
            startPage: startPage,
            loadPage: { [self] pageIndex in
                if pageIndex == startPage {
                    return initialRows
                }

                let buildsPage = try await listBuildsService.listBuilds(
                    fullHandle: resolvedFullHandle,
                    serverURL: serverURL,
                    gitBranch: gitBranch,
                    status: status,
                    scheme: scheme,
                    configuration: configuration,
                    tags: tags,
                    values: values,
                    page: pageIndex + 1, // API uses 1-indexed pages
                    pageSize: pageSize
                )

                return buildsPage.builds.map { build in
                    [
                        build.id,
                        build.status.rawValue,
                        build.scheme ?? "-",
                        build.configuration ?? "-",
                        formatDuration(build.duration),
                        build.is_ci ? "Yes" : "No",
                        formatDate(build.inserted_at),
                    ]
                }
            }
        )
    }

    private func formatDuration(_ milliseconds: Int) -> String {
        if milliseconds < 1000 {
            return "\(milliseconds)ms"
        } else if milliseconds < 60000 {
            let seconds = Double(milliseconds) / 1000.0
            return String(format: "%.1fs", seconds)
        } else {
            let minutes = milliseconds / 60000
            let seconds = (milliseconds % 60000) / 1000
            return "\(minutes)m \(seconds)s"
        }
    }

    private func formatDate(_ date: Date) -> String {
        let outputFormatter = DateFormatter()
        outputFormatter.dateStyle = .short
        outputFormatter.timeStyle = .short
        return outputFormatter.string(from: date)
    }
}

