import Foundation
import Noora
import Path
import TuistConfigLoader
import TuistEnvironment
import TuistNooraExtension
import TuistServer

protocol TestShowCommandServicing {
    func run(
        project: String?,
        testRunId: String,
        path: String?,
        json: Bool
    ) async throws
}

enum TestShowCommandServiceError: Equatable, LocalizedError {
    case missingFullHandle

    var errorDescription: String? {
        switch self {
        case .missingFullHandle:
            return "We couldn't show the test run because the project is missing. You can pass either its value or a path to a Tuist project."
        }
    }
}

struct TestShowCommandService: TestShowCommandServicing {
    private let getTestRunService: GetTestRunServicing
    private let serverEnvironmentService: ServerEnvironmentServicing
    private let configLoader: ConfigLoading

    init(
        getTestRunService: GetTestRunServicing = GetTestRunService(),
        serverEnvironmentService: ServerEnvironmentServicing = ServerEnvironmentService(),
        configLoader: ConfigLoading = ConfigLoader()
    ) {
        self.getTestRunService = getTestRunService
        self.serverEnvironmentService = serverEnvironmentService
        self.configLoader = configLoader
    }

    func run(
        project: String?,
        testRunId: String,
        path: String?,
        json: Bool
    ) async throws {
        let directoryPath: AbsolutePath = try await Environment.current.pathRelativeToWorkingDirectory(path)

        let config = try await configLoader.loadConfig(path: directoryPath)
        guard let resolvedFullHandle = project ?? config.fullHandle else {
            throw TestShowCommandServiceError.missingFullHandle
        }

        let serverURL = try serverEnvironmentService.url(configServerURL: config.url)

        let run = try await getTestRunService.getTestRun(
            fullHandle: resolvedFullHandle,
            testRunId: testRunId,
            serverURL: serverURL
        )

        if json {
            try Noora.current.json(run)
            return
        }

        let info = formatRunInfo(run)
        Noora.current.passthrough("\(info)")
        Noora.current
            .passthrough(
                "\nNext steps:\n ▸ Run \(.command("tuist test case run list --test-run-id \(run.id)")) to see the test case runs\n"
            )
    }

    private func formatRunInfo(_ run: ServerTestRun) -> String {
        var info: [String] = []

        // Status header
        let statusLabel: String
        switch run.status {
        case .success: statusLabel = "passed"
        case .failure: statusLabel = "failed"
        case .skipped: statusLabel = "skipped"
        }
        info.append("Test Run (\(statusLabel))".bold())

        // Result
        info.append("")
        info.append("Result".bold())
        info.append("  Status:       \(run.status.rawValue)")
        info.append("  Duration:     \(Formatters.formatDuration(run.duration))")
        info.append("  Flaky:        \(run.is_flaky ? "Yes" : "No")")

        // Test Metrics
        info.append("")
        info.append("Test Cases".bold())
        info.append("  Total:        \(run.total_test_count)")
        info.append("  Failed:       \(run.failed_test_count)")
        info.append("  Flaky:        \(run.flaky_test_count)")
        info.append("  Avg Duration: \(Formatters.formatDuration(run.avg_test_duration))")

        // Environment
        if run.macos_version != nil || run.xcode_version != nil || run.device_name != nil {
            info.append("")
            info.append("Environment".bold())
            if let deviceName = run.device_name, !deviceName.isEmpty {
                info.append("  Device:       \(deviceName)")
            }
            if let macosVersion = run.macos_version, !macosVersion.isEmpty {
                info.append("  macOS:        \(macosVersion)")
            }
            if let xcodeVersion = run.xcode_version, !xcodeVersion.isEmpty {
                info.append("  Xcode:        \(xcodeVersion)")
            }
        }

        // Context
        info.append("")
        info.append("Context".bold())
        info.append("  CI:           \(run.is_ci ? "Yes" : "No")")
        if let scheme = run.scheme, !scheme.isEmpty {
            info.append("  Scheme:       \(scheme)")
        }
        if let gitBranch = run.git_branch, !gitBranch.isEmpty {
            info.append("  Branch:       \(gitBranch)")
        }
        if let gitCommitSha = run.git_commit_sha, !gitCommitSha.isEmpty {
            info.append("  Commit:       \(gitCommitSha)")
        }
        if let ranAt = run.ran_at {
            info.append("  Ran At:       \(Formatters.formatDate(ranAt))")
        }

        // IDs
        info.append("")
        info.append("IDs".bold())
        info.append("  Run:          \(run.id)")

        return info.joined(separator: "\n") + "\n"
    }
}

import ArgumentParser
import Foundation
import Path
import TuistEnvKey
import TuistNooraExtension

public struct TestCaseRunListCommand: AsyncParsableCommand, NooraReadyCommand {
    public init() {}
    public static var configuration: CommandConfiguration {
        CommandConfiguration(
            commandName: "list",
            abstract: "Lists runs for a test case."
        )
    }

    @Argument(
        help: "The test case identifier. Either a UUID or the format Module/Suite/TestCase (or Module/TestCase).",
        envKey: .testCaseRunListIdentifier
    )
    var testCaseIdentifier: String?

    @Option(
        name: [.customLong("project"), .customShort("P")],
        help: "The full handle of the project. Must be in the format of account-handle/project-handle.",
        envKey: .testCaseRunListProject
    )
    var project: String?

    @Option(
        name: .shortAndLong,
        help: "The path to the directory or a subdirectory of the project.",
        completion: .directory,
        envKey: .testCaseRunListPath
    )
    var path: String?

    @Flag(
        name: .long,
        help: "Filter by flaky runs.",
        envKey: .testCaseRunListFlaky
    )
    var flaky: Bool = false

    @Option(
        name: .long,
        help: "Filter by test run ID.",
        envKey: .testCaseRunListTestRunId
    )
    var testRunId: String?

    @Option(
        name: .long,
        help: "The page number to fetch (1-indexed).",
        envKey: .testCaseRunListPage
    )
    var page: Int?

    @Option(
        name: .long,
        help: "The number of runs per page. Defaults to 10.",
        envKey: .testCaseRunListPageSize
    )
    var pageSize: Int?

    @Flag(
        help: "The output in JSON format.",
        envKey: .testCaseRunListJson
    )
    var json: Bool = false

    public var jsonThroughNoora: Bool = true

    public func run() async throws {
        try await TestCaseRunListCommandService().run(
            project: project,
            path: path,
            testCaseIdentifier: testCaseIdentifier,
            flaky: flaky,
            testRunId: testRunId,
            page: page,
            pageSize: pageSize,
            json: json
        )
    }
}

import Foundation
import Noora
import Path
import TuistConfigLoader
import TuistEnvironment
import TuistNooraExtension
import TuistServer

protocol TestCaseRunListCommandServicing {
    func run(
        project: String?,
        path: String?,
        testCaseIdentifier: String?,
        flaky: Bool,
        testRunId: String?,
        page: Int?,
        pageSize: Int?,
        json: Bool
    ) async throws
}

enum TestCaseRunListCommandServiceError: Equatable, LocalizedError {
    case missingFullHandle

    var errorDescription: String? {
        switch self {
        case .missingFullHandle:
            return "We couldn't list test case runs because the project is missing. You can pass either its value or a path to a Tuist project."
        }
    }
}

struct TestCaseRunListCommandService: TestCaseRunListCommandServicing {
    private let getTestCaseService: GetTestCaseServicing
    private let listTestCaseRunsService: ListTestCaseRunsServicing
    private let serverEnvironmentService: ServerEnvironmentServicing
    private let configLoader: ConfigLoading

    init(
        getTestCaseService: GetTestCaseServicing = GetTestCaseService(),
        listTestCaseRunsService: ListTestCaseRunsServicing = ListTestCaseRunsService(),
        serverEnvironmentService: ServerEnvironmentServicing = ServerEnvironmentService(),
        configLoader: ConfigLoading = ConfigLoader()
    ) {
        self.getTestCaseService = getTestCaseService
        self.listTestCaseRunsService = listTestCaseRunsService
        self.serverEnvironmentService = serverEnvironmentService
        self.configLoader = configLoader
    }

    func run(
        project: String?,
        path: String?,
        testCaseIdentifier: String?,
        flaky: Bool,
        testRunId: String?,
        page: Int?,
        pageSize: Int?,
        json: Bool
    ) async throws {
        let directoryPath: AbsolutePath = try await Environment.current.pathRelativeToWorkingDirectory(path)

        let config = try await configLoader.loadConfig(path: directoryPath)
        guard let resolvedFullHandle = project ?? config.fullHandle else {
            throw TestCaseRunListCommandServiceError.missingFullHandle
        }

        let serverURL = try serverEnvironmentService.url(configServerURL: config.url)

        let pageSize = pageSize ?? 10
        let startPage = (page ?? 1) - 1

        let testCaseId: String?
        if let testCaseIdentifier {
            switch try TestCaseIdentifier(testCaseIdentifier) {
            case let .name(moduleName, suiteName, testName):
                let testCase = try await getTestCaseService.getTestCaseByName(
                    fullHandle: resolvedFullHandle,
                    moduleName: moduleName,
                    name: testName,
                    suiteName: suiteName,
                    serverURL: serverURL
                )
                testCaseId = testCase.id
            case let .id(id):
                testCaseId = id
            }
        } else {
            testCaseId = nil
        }

        let initialPage = try await listTestCaseRunsService.listTestCaseRuns(
            fullHandle: resolvedFullHandle,
            serverURL: serverURL,
            testCaseId: testCaseId,
            flaky: flaky ? true : nil,
            testRunId: testRunId,
            page: startPage + 1,
            pageSize: pageSize
        )

        let initialRuns = initialPage.test_case_runs

        if json {
            try Noora.current.json(initialRuns)
            return
        }

        if initialRuns.isEmpty {
            var message: String
            if let testCaseIdentifier {
                message = "No test case runs found for \(testCaseIdentifier)"
            } else if let testRunId {
                message = "No test case runs found for test run \(testRunId)"
            } else {
                message = "No test case runs found"
            }
            if flaky { message += " (flaky only)" }
            Noora.current.passthrough(TerminalText(stringLiteral: message + "."))
            return
        }

        let totalPages = initialPage.pagination_metadata.total_pages ?? 1

        let showNameColumns = testCaseId == nil
        let headers: [String]
        if showNameColumns {
            headers = ["ID", "Name", "Module", "Status", "Duration", "CI", "Flaky", "Branch", "Commit", "Ran At"]
        } else {
            headers = ["ID", "Status", "Duration", "CI", "Flaky", "Branch", "Commit", "Ran At"]
        }

        let initialRows = initialRuns.map { formatRunRow($0, showNameColumns: showNameColumns) }

        try await Noora.current.paginatedTable(
            headers: headers,
            pageSize: pageSize,
            totalPages: totalPages,
            startPage: startPage,
            loadPage: { [self] pageIndex in
                if pageIndex == startPage {
                    return initialRows
                }

                let runsPage = try await listTestCaseRunsService.listTestCaseRuns(
                    fullHandle: resolvedFullHandle,
                    serverURL: serverURL,
                    testCaseId: testCaseId,
                    flaky: flaky ? true : nil,
                    testRunId: testRunId,
                    page: pageIndex + 1,
                    pageSize: pageSize
                )

                return runsPage.test_case_runs.map { formatRunRow($0, showNameColumns: showNameColumns) }
            }
        )
    }

    private func formatRunRow(
        _ run: Components.Schemas.TestCaseRun,
        showNameColumns: Bool
    ) -> [String] {
        var row = [run.id]

        if showNameColumns {
            let name = [run.module_name, run.suite_name, run.name]
                .compactMap { $0 }
                .joined(separator: "/")
            row.append(name)
            row.append(run.module_name)
        }

        row.append(contentsOf: [
            run.status.rawValue,
            Formatters.formatDuration(run.duration),
            run.is_ci ? "Yes" : "No",
            run.is_flaky ? "Yes" : "No",
            run.git_branch ?? "-",
            run.git_commit_sha.map { String($0.prefix(7)) } ?? "-",
            run.ran_at.map { Formatters.formatDate($0) } ?? "-",
        ])

        return row
    }
}
